/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
parm(in:&Mode, in:&EmpCod, in:&ProCod);

NoAccept(ProLojVirIntId);
NoAccept(ProLojVirIntSeo);
NoAccept(ProLojVirIntUri);
NoAccept(ProLojVirDtaAlt);
NoAccept(ProLojVirDtaCri);
NoAccept(ProVlrCus);
NoAccept(ProVlrUltCmp);
NoAccept(ProCod);
EmpCod = &EmpCod if not &EmpCod.IsEmpty();
noaccept(EmpCod) if not &EmpCod.IsEmpty();
ProCod = &ProCod if not &ProCod.IsEmpty();
BtnReceitaProduto.Visible = True If (&mode = TrnMode.Update and &ProTipCus = TipoCusto.Receita);
BtnReceitaProduto.Visible = False If Not (&mode = TrnMode.Update and &ProTipCus = TipoCusto.Receita);
BtnPrecoVenda.Visible = True If (&mode = TrnMode.Update);
BtnPrecoVenda.Visible = False If Not (&mode = TrnMode.Update);
BtnimagemProduto.Visible = True If (&mode = TrnMode.Update);
BtnimagemProduto.Visible = False If Not (&mode = TrnMode.Update);
Accept(&EstQtd);
Accept(&ProVlrCus);
Accept(&TabPrc1);
Accept(&ProdutoComGrade);
ProVlrPar_Cell.Class = !'col-xs-12 DataContentCell DscTop' if not(ProObrAnp = Status_SimNao.Sim and ProCodAnp = 210203001);
ProVlrPar_Cell.Class = !'col-xs-12 RequiredDataContentCell DscTop' if ProObrAnp = Status_SimNao.Sim and ProCodAnp = 210203001;
ProPerGnn_Cell.Class = !'col-xs-12 DataContentCell DscTop' if not(ProObrAnp = Status_SimNao.Sim and ProCodAnp = 210203001);
ProPerGnn_Cell.Class = !'col-xs-12 RequiredDataContentCell DscTop' if ProObrAnp = Status_SimNao.Sim and ProCodAnp = 210203001;
ProPerGni_Cell.Class = !'col-xs-12 DataContentCell DscTop' if not(ProObrAnp = Status_SimNao.Sim and ProCodAnp = 210203001);
ProPerGni_Cell.Class = !'col-xs-12 RequiredDataContentCell DscTop' if ProObrAnp = Status_SimNao.Sim and ProCodAnp = 210203001;
ProDscAnp_Cell.Class = !'col-xs-12 DataContentCell DscTop' if not(ProObrAnp = Status_SimNao.Sim);
ProDscAnp_Cell.Class = !'col-xs-12 RequiredDataContentCell DscTop' if ProObrAnp = Status_SimNao.Sim;
ProCodAnp_Cell.Class = !'col-xs-12 DataContentCell DscTop' if not(ProObrAnp = Status_SimNao.Sim);
ProCodAnp_Cell.Class = !'col-xs-12 RequiredDataContentCell DscTop' if ProObrAnp = Status_SimNao.Sim;
ProEstTip.Visible = &proCod = 0;
ProEstTip_Cell.Class = !'Invisible' If not(&proCod = 0);
ProEstTip_Cell.Class = !'col-xs-12 col-sm-6 RequiredDataContentCell' If &proCod = 0;
ProRef.Visible = &TCon065_BloquearAlteracaoCodigo <> 'S' or ( &TCon065_BloquearAlteracaoCodigo = 'S'  and &mode <> TrnMode.Insert);
ProRef_Cell.Class = !'Invisible' If not(&TCon065_BloquearAlteracaoCodigo <> 'S' or ( &TCon065_BloquearAlteracaoCodigo = 'S'  and &mode <> TrnMode.Insert));
ProRef_Cell.Class = !'col-xs-12 DataContentCell' If &TCon065_BloquearAlteracaoCodigo <> 'S' or ( &TCon065_BloquearAlteracaoCodigo = 'S'  and &mode <> TrnMode.Insert);
&VarProEstTip.Visible = &ProCod <> 0;
VarProEstTip_Cell.Class = !'Invisible' If not(&ProCod <> 0);
VarProEstTip_Cell.Class = !'col-xs-12 col-sm-6 RequiredDataContentCell' If &ProCod <> 0;
&PrincipalMensagem.Visible = not &PrincipalMensagem.isEmpty();
PrincipalMensagem_Cell.Class = !'Invisible' If not(not &PrincipalMensagem.isEmpty());
PrincipalMensagem_Cell.Class = !'col-xs-12 DataContentCell' If not &PrincipalMensagem.isEmpty();
DVPanel_UnnamedTable1_Cell.Class = !'Invisible' If not(&mode = TrnMode.insert);
DVPanel_UnnamedTable1_Cell.Class = !'col-xs-12' If &mode = TrnMode.insert;
tbComGrade.Visible = (&TCon054_TrabalharGrades = 'S');
tbSemGrade.Visible = (&TCon054_TrabalharGrades <> 'S' or &ProdutoComGrade = False);
tbEst.Visible = (ProEstTip = TipoEstoque.ATUALIZAR_ESTOQUE or ProEstTip.isnull());
tbMarkup.Visible = (&TCon083_Markup = 'S');
tbAcrescimo.Visible = (&TCon083_Markup <> 'S');
TableNFPe_MT.Visible = (&TCon119_DestacaObrigacaoNFPe = 'S');
tbsts.Visible = (&TCon065_BloquearAlteracaoCodigo = 'S' and &mode = Trnmode.Insert);
tbref.Visible = (&TCon065_BloquearAlteracaoCodigo <> 'S' or ( &TCon065_BloquearAlteracaoCodigo = 'S'  and &mode <> TrnMode.Insert));
Error(Format('WWP_RequiredAttribute','Valor de Partida')) if (ProObrAnp = Status_SimNao.Sim and ProCodAnp = 210203001) AND ProVlrPar.IsEmpty();
Error(Format('WWP_RequiredAttribute','Percentual GNN')) if (ProObrAnp = Status_SimNao.Sim and ProCodAnp = 210203001) AND ProPerGnn.IsEmpty();
Error(Format('WWP_RequiredAttribute','Percentual GNI')) if (ProObrAnp = Status_SimNao.Sim and ProCodAnp = 210203001) AND ProPerGni.IsEmpty();
Error(Format('WWP_RequiredAttribute','Descrição Produto ANP')) if (ProObrAnp = Status_SimNao.Sim) AND ProDscAnp.IsEmpty();
Error(Format('WWP_RequiredAttribute','Código Produto ANP')) if (ProObrAnp = Status_SimNao.Sim) AND ProCodAnp.IsEmpty();
Error(Format('WWP_RequiredAttribute','Tipo de Custo')) if ProTipCus.IsEmpty();
Error(Format('WWP_RequiredAttribute','Setor Produto')) if ProSetCod.IsEmpty();
Error(Format('WWP_RequiredAttribute','Codigo')) if GrupCod.IsEmpty();
Error(Format('WWP_RequiredAttribute','Definição')) if ProTipDef.IsEmpty();
Error(Format('WWP_RequiredAttribute','Embalagem')) if ProEmbCod.IsEmpty();
Error(Format('WWP_RequiredAttribute','Marca Código')) if MarCod.IsEmpty();
Error(Format('WWP_RequiredAttribute','Produto Descrição')) if ProNom.IsEmpty();
Default(EmpCod,&context.EmpCod);
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */

Default(ProPadForCod, 0);
default(EmpCod, &Context.EmpCod);
Default(ProTipCus, TipoCusto.UltimaCompra);
Default(ProSetCod, &SetCod);
Default(MarCod, &MarCod);
//Default(NcmCod, 99);
//Default(ProCatCod, 1 );
Default(ProSts, Status_Produto.ATIVO);
Default(ProTipDef, Definicao.REVENDA);
Default(ProDesMax, 100);
Default(ProEmbCod, 1);
Default(ProReqQtd, false);
Default(ProReqVlr, false);
Default(ProDtaCad, serverdate());
Default(ProPadUltCmp, 'C');
Default(GrupCod, &GrupCod);
Default(ProEstTip, TipoEstoque.ATUALIZAR_ESTOQUE);

Default(ProInfCmp, &ProInfCmp); 

Prompt(PromptNcm, NcmCod);
prompt(PromptFornecedores, EmpCod, ProPadForCod);
prompt(promptMarcaVarchar, EmpCod, &MarCod, MarCod);
prompt(promptSetorVarchar, EmpCod, &SetCod, ProSetCod);
Prompt(promptEmbalagem, EmpCod, ProEmbCod);
prompt(promptCategoriaProdutosSugg, EmpCod, &GrupCod, &GrupAnaSin, GrupCod);

//CASO INFORMOU CODIGO VALIDA
verificaCodigoDisponivelProduto.Call(EmpCod, ProCod, &IsDisponivel) 
	if &Mode = TrnMode.Insert and after(ProCod);

Error('Código já utilizado, Informe outro Código para o Cadastro.') 
	If &IsDisponivel = false and &Mode = TrnMode.Insert and after(ProCod);

//SENAO LOCALIZA UM DISPONIVEL
UltimoCodigoEspecial.Call(domParCod.PRODUTO, EmpCod, 0, ProCod)
	If insert and ProCod.IsEmpty() and &TCon068_NaoRetornaCodigo <> 'N' 
	on AfterValidate;

UltimoCodigoEspecial.Call(domParCod.PRODUTO, EmpCod, 0, ProCod)
	If insert and ProCod.IsEmpty() and &TCon068_NaoRetornaCodigo = 'N' 
	on AfterValidate;
//GRAVA CODIGO SELECIONADO
//ProCod = &NewProCod
//	If insert and (ProCod.IsEmpty()  or ProCod.IsNull())
//	on AfterValidate;

