//GXUITabsPanel_tbtabsda.ShowTab(4) if ProObrAnp = Status_SimNao.Sim ;

//Error('Tipo de Custo Receita, Permitido somente para Produtos Definidos como Fabricação Própria ou Sub-Produto!') 
//	if not ProTipDef in (Definicao.FABRICADO, Definicao.SUBPRODUTO) and (ProTipCus = TipoCusto.Receita);

Error('Tipo Custo: CUSTO PRODUTO MOVIMENTA ESTOQUE, Somente permitido para Produtos com Tipo Estoque: MOVIMENTAR ESTOQUES OUTRO PRODUTO!') 
	if ProTipCus = TipoCusto.CustoProdutoEstoque and (ProCod = ProEstProCod or ProEstProCod = 0);

Error(ProEstIsRec) 
	if not ProEstIsRec.IsEmpty() and ProTipCus = TipoCusto.CustoProdutoEstoque ;

Default(ProIMC, &ProIMC);
Default(ProIMCTot, &ProIMC);


//## Referencia Repetido
ValidaCodigoReferenciaRepetido.Call(EmpCod, ProCod,  1, ProRef, &RepetidoReferenciaMensagem) 
	if After(ProRef) and not ProRef.IsEmpty();

error(&RepetidoReferenciaMensagem)
	if (not &RepetidoReferenciaMensagem.IsEmpty()) and (not ProRef.IsEmpty()) and after(ProRef);


//## EAN 13
ProDtaHorUltMod = now();

ValidaCodigoReferenciaRepetido.Call(EmpCod,ProCod, 1, ProBar, &RepetidoEanMensagem) 
	if After(ProBar) and not ProBar.IsEmpty();

error(&RepetidoEanMensagem) 
	if (not &RepetidoEanMensagem.IsEmpty()) and (not ProBar.IsEmpty()) and after(ProBar);

ValidaEan13.Call(ProCod, ProBar, &ProBar, &ErroEan13Mensagem) 
	if after(ProBar);// and (not ProBar.IsEmpty());

msg(&ErroEan13Mensagem) 
	if not &ErroEan13Mensagem.IsEmpty() and &RepetidoEanMensagem.IsEmpty() and (not ProBar.IsEmpty()) and after(ProBar);


ProRef.Enabled = &TCon065_BloquearAlteracaoCodigo <> 'S';

